import React, { useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { authService } from "../services";
import "../styles/Dashboard.css";

const UserDashboard = () => {
  const user = authService.getCurrentUser();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const handleLogout = () => {
    authService.logout();
    navigate("/user/login");
  };

  const menuItems = [
    { name: "Dashboard", icon: "📊", path: "/user/dashboard" },
    { name: "Loads", icon: "📦", path: "/loads" },
    { name: "Create Load", icon: "➕", path: "/create-load" },
  ];

  const isActive = (path) => location.pathname === path;

  return (
    <div className="dashboard-container">
      {/* Sidebar */}
      <aside className={`dashboard-sidebar ${sidebarOpen ? "open" : "closed"}`}>
        <div className="sidebar-header">
          <h2 className="sidebar-title">📦 Loads</h2>
          <button
            className="sidebar-toggle"
            onClick={() => setSidebarOpen(!sidebarOpen)}
          >
            {sidebarOpen ? "✕" : "☰"}
          </button>
        </div>

        <nav className="sidebar-menu">
          {menuItems.map((item) => (
            <button
              key={item.path}
              className={`menu-item ${isActive(item.path) ? "active" : ""}`}
              onClick={() => {
                navigate(item.path);
                if (window.innerWidth < 768) setSidebarOpen(false);
              }}
            >
              <span className="menu-icon">{item.icon}</span>
              {sidebarOpen && <span className="menu-label">{item.name}</span>}
            </button>
          ))}
        </nav>

        <div className="sidebar-footer">
          <button onClick={handleLogout} className="btn-logout">
            🚪 {sidebarOpen && "Logout"}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="dashboard-main">
        <div className="dashboard-header user-header">
          <div className="header-top">
            <h1>User Dashboard</h1>
            <p className="subtitle">Welcome, {user?.name}!</p>
          </div>
          <div className="header-actions">
            <button
              onClick={() => navigate("/create-load")}
              className="btn-primary"
            >
              Create New Load
            </button>
          </div>
        </div>

        <div className="dashboard-content">
          <div className="info-card user-info">
            <h3>Load Management System</h3>
            <p>Manage your loads efficiently with our platform.</p>
            <ul>
              <li>Create and manage loads</li>
              <li>Track load status</li>
              <li>View all available loads</li>
              <li>Edit or delete your loads</li>
            </ul>
            <button onClick={() => navigate("/loads")} className="btn-primary">
              Go to Loads
            </button>
          </div>

          <div className="quick-stats">
            <div className="stat-card">
              <h4>Email</h4>
              <p>{user?.email}</p>
            </div>
            <div className="stat-card">
              <h4>Role</h4>
              <p className="role-badge user-badge">
                {user?.role?.toUpperCase()}
              </p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default UserDashboard;
